package sdks.io.synthetic.org.apache.beam.sdk.io.synthetic;

public static class Options extends SyntheticOptions { @ JsonProperty public double outputRecordsPerInputRecord ; @ JsonProperty public boolean preservesInputKeyDistribution ; @ JsonProperty public long maxWorkerThroughput = - 1 ; @ JsonProperty public long perBundleDelay = 0 ; @ JsonProperty public DelayType perBundleDelayType = DelayType . SLEEP ; @ JsonProperty public boolean reportThrottlingMicros ; @ Override public void validate ( ) { super . validate ( ) ; checkArgument ( outputRecordsPerInputRecord >= 0 , "outputRecordsPerInputRecord should be a non-negative number, but found %s." , outputRecordsPerInputRecord ) ; checkArgument ( perBundleDelay >= 0 , "perBundleDelay should be a non-negative number, but found %s." , perBundleDelay ) ; if ( maxWorkerThroughput >= 0 ) { checkArgument ( perBundleDelay == 0 , "maxWorkerThroughput and perBundleDelay cannot be enabled simultaneously." ) ; } } }